PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE cards (
      id TEXT PRIMARY KEY,
      name TEXT NOT NULL,
      set_code TEXT NOT NULL,
      set_name TEXT NOT NULL,
      local_id TEXT NOT NULL,
      folder_name TEXT NOT NULL,
      variants TEXT DEFAULT 'normal',
      sizes TEXT DEFAULT 'sm,md,lg,xl'
    );
CREATE TABLE decks (
    id TEXT PRIMARY KEY,
    user_id TEXT NOT NULL,
    name TEXT NOT NULL,
    items JSON NOT NULL,        -- Changed from TEXT to JSON
    is_active BOOLEAN DEFAULT 0,
    created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
    updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE subscriptions (
  user_id TEXT PRIMARY KEY,
  tier TEXT DEFAULT 'free',  -- 'free', 'pro', 'founding'
  status TEXT DEFAULT 'active', -- 'active', 'cancelled', 'expired'
  started_at DATETIME,
  expires_at DATETIME,
  stripe_customer_id TEXT,
  stripe_subscription_id TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
, stripe_payment_intent_id TEXT, founding_number INTEGER);
CREATE TABLE user_export_limits (
  user_id TEXT PRIMARY KEY,
  welcome_credits_used INTEGER DEFAULT 0,
  turbo_exports_used INTEGER DEFAULT 0,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
CREATE TABLE user_exports (
  user_id TEXT NOT NULL,
  date TEXT NOT NULL,
  count INTEGER DEFAULT 1,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (user_id, date)
);
CREATE TABLE user_profiles (
  user_id TEXT PRIMARY KEY,  -- Clerk user ID
  settings JSON,             -- Print settings JSON
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP,
  updated_at DATETIME DEFAULT CURRENT_TIMESTAMP
);
COMMIT;